                    self.infcx,
                    &obligation.with(self.tcx, trait_pred),
                );
                let has_non_region_infer = trait_pred
                    .skip_binder()
                    .trait_ref
                    .args
                    .types()
                    .any(|t| !t.is_ty_or_numeric_infer());
